index.html<pre><code>&lt;!DOCTYPE html&gt;
&lt;html lang="en"&gt;
&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;

    &lt;title&gt;Your game name&lt;/title&gt;
    &lt;script src="/app.js" type="module"&gt;&lt;/script&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;canvas id="yourCanvasId"&gt;&lt;/canvas&gt;
&lt;/body&gt;
&lt;/html&gt;
</code></pre> app.js<pre><code>import * as cazan from "./path/to/cazan.js"

function runApp() {
    let game = cazan.setup("#yourCanvasId", "2d")
    game.setSize(600, 350)

    let rectangle = new cazan.shapes.Shape(game, {x: 10, y: 10}, {x: 50, y: 50})

    game.update()
}

window.addEventListener("load", runApp);
</code></pre>
